"use client";
import { v4 as uuidv4 } from "uuid";

import { useEffect, useState } from "react";
import {useAiSettingsStore} from "@/store/useAiSettingsStore";
import { Save } from "lucide-react";
import { Button } from "@borsch/ui/components/button";
import { Label } from "@borsch/ui/components/label";
import { Input } from "@borsch/ui/components/input";
import { Textarea } from "@borsch/ui/components/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@borsch/ui/components/select";
import { getDb } from "@borsch/db-local";

export default function AiSettingsPage() {
  const { settings, fetchSettings, updateSettings, isLoading } = useAiSettingsStore();
  const [formData, setFormData] = useState<Record<string, any>>({
    provider: "gemini",
    model_name: "gemini-2.5-flash",
    api_key: "",
    base_url: "",
    prompt_base: "",
    prompt_custom: "",
    prompt_forbidden: "",
    is_developer_mode: false,
  });
  const [isSaving, setIsSaving] = useState(false);

  useEffect(() => {
    fetchSettings();
  }, [fetchSettings]);

  useEffect(() => {
    if (settings) {
      setFormData({
        provider: settings.provider || "gemini",
        model_name: settings.model_name || "",
        api_key: settings.api_key || "",
        base_url: settings.base_url || "",
        prompt_base: settings.prompt_base || "",
        prompt_custom: settings.prompt_custom || "",
        prompt_forbidden: settings.prompt_forbidden || "",
        is_developer_mode: settings.is_developer_mode || false,
      });
    }
  }, [settings]);

  // Create default row if missing
  const initDb = async () => {
    const db = await getDb();
    await db.execute(
      `INSERT INTO ai_settings (id, provider, model_name, prompt_base, sync_status) 
       VALUES ($1, $2, $3, $4, 'pending_insert')`,
      [uuidv4(), 'gemini', 'gemini-2.5-flash', 'Ты профессиональный ИИ-ассистент менеджера кухни.']
    );
    await fetchSettings();
  };

  const handleSave = async () => {
    setIsSaving(true);
    try {
      if (!settings?.id) {
         await initDb();
      } else {
         await updateSettings(formData);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <div className="flex-1 overflow-y-auto p-8 relative">
      <div className="max-w-4xl mx-auto space-y-8 pb-32">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Настройки ИИ-Агента</h1>
          <p className="text-muted-foreground mt-2">
            Настройте подключение к языковой модели (LLM) и задайте правила поведения агента внутри админки.
          </p>
        </div>

        {/* CONNECTION SETTINGS */}
        <div className="grid gap-6 p-6 border rounded-xl bg-card">
          <h2 className="text-xl font-semibold">Подключение к Провайдеру</h2>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label>Провайдер</Label>
              <Select 
                value={formData.provider} 
                onValueChange={(val: any) => setFormData({ ...formData, provider: val })}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Выберите провайдера" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="gemini">Google Gemini</SelectItem>
                  <SelectItem value="openai">OpenAI / Claude API</SelectItem>
                  <SelectItem value="local">Local (Apple MLX / Ollama / LM Studio)</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-2">
              <Label>Название Модели</Label>
              <Input 
                placeholder="gemini-2.5-flash, gpt-4o, qwen2.5:1.5b..." 
                value={formData.model_name}
                onChange={(e) => setFormData({ ...formData, model_name: e.target.value })}
              />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
             <div className="space-y-2">
              <Label>API Ключ (опционально для Local)</Label>
              <Input 
                type="password"
                placeholder="sk-..." 
                value={formData.api_key}
                onChange={(e) => setFormData({ ...formData, api_key: e.target.value })}
              />
            </div>

            <div className="space-y-2">
              <Label>Base URL (Локальный сервер или Proxy)</Label>
              <Input 
                placeholder="http://127.0.0.1:8080/v1 (MLX) или 11434 (Ollama)" 
                value={formData.base_url}
                onChange={(e) => setFormData({ ...formData, base_url: e.target.value })}
                disabled={formData.provider === 'gemini'}
              />
              <p className="text-xs text-muted-foreground mt-1">Используйте http://127.0.0.1:8080/v1 для Apple MLX_lm.serve или другой локальный адрес.</p>
            </div>
          </div>
        </div>

        {/* PROMPTS */}
        <div className="grid gap-6 p-6 border rounded-xl bg-card">
          <h2 className="text-xl font-semibold">Системные Промпты (Правила поведения)</h2>

          <div className="space-y-2">
            <Label>1. Базовая роль (Кто он и что делает)</Label>
            <Textarea 
              className="h-24"
              placeholder="Ты профессиональный шеф-повар и ИИ-ассистент..." 
              value={formData.prompt_base}
              onChange={(e) => setFormData({ ...formData, prompt_base: e.target.value })}
            />
          </div>

          <div className="space-y-2">
            <Label>2. Кастомные настройки (Особенности ресторана/клиента)</Label>
            <Textarea 
               className="h-24"
              placeholder="Мы готовим только веганскую еду. Общайся неформально на 'Ты'." 
              value={formData.prompt_custom}
              onChange={(e) => setFormData({ ...formData, prompt_custom: e.target.value })}
            />
          </div>

          <div className="space-y-2 border border-red-500/30 p-4 rounded-lg bg-red-500/5">
            <Label className="text-red-500 font-bold">3. Форбидден-блок (ЧЕГО ДЕЛАТЬ КАТЕГОРИЧЕСКИ НЕЛЬЗЯ)</Label>
            <Textarea 
               className="h-24 border-red-500/20"
              placeholder="Никогда не удаляй базу, не давай скидки больше 5%, не придумывай товары." 
              value={formData.prompt_forbidden}
              onChange={(e) => setFormData({ ...formData, prompt_forbidden: e.target.value })}
            />
            <p className="text-xs text-red-500/70 mt-1">Используется агентом как строгие красные флаги.</p>
          </div>
        </div>
        {/* DEVELOPER MODE */}
        <div className="grid gap-6 p-6 border rounded-xl bg-card border-blue-500/30">
          <div className="flex items-start gap-4">
            <div className="pt-1">
               <input 
                 type="checkbox" 
                 className="w-5 h-5 accent-blue-500 rounded cursor-pointer" 
                 checked={formData.is_developer_mode}
                 onChange={(e) => setFormData({ ...formData, is_developer_mode: e.target.checked })}
               />
            </div>
            <div>
              <h2 className="text-xl font-semibold text-blue-500 dark:text-blue-400">Режим Разработчика (AI Developer Mode)</h2>
              <p className="text-sm text-muted-foreground mt-1">Если включено, ИИ получает доступ к файловой системе и может выполнять скрипты на вашем компьютере для модификации проекта. Включайте только если доверяете системным промптам и модели.</p>
            </div>
          </div>

          {formData.is_developer_mode && (
            <div className="mt-4 p-4 bg-muted/50 rounded-lg text-sm space-y-3">
              <h3 className="font-bold border-b pb-2 mb-3">Доступные технические инструменты (Tools API):</h3>
              <ul className="list-disc pl-5 space-y-2 text-muted-foreground">
                <li><strong className="text-foreground">read_local_file(path)</strong>: Чтение исходного кода компонентов или любых локальных файлов проекта.</li>
                <li><strong className="text-foreground">write_local_file(path, content)</strong>: Перезапись или создание новых файлов (например, добавить новый UI компонент в проект).</li>
                <li><strong className="text-foreground">execute_local_command(cmd, args)</strong>: Выполнение произвольных shell команд напрямую на устройстве (например <code>git commit</code>, <code>npm run build</code>, <code>npm install</code>).</li>
              </ul>
            </div>
          )}
        </div>

      </div>

      <div className="fixed bottom-0 left-[240px] right-0 p-4 bg-background/80 backdrop-blur-md border-t flex justify-between items-center z-10">
        <div className="text-sm text-muted-foreground">
          {isSaving ? "Сохранение..." : settings ? "Настройки загружены" : "Загрузка..."}
        </div>
        <Button onClick={handleSave} disabled={isSaving || isLoading}>
          <Save className="w-4 h-4 mr-2" />
          Сохранить настройки
        </Button>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState, useMemo } from "react";
import { 
  PlusCircle, 
  CalendarDays, 
  TrendingUp, 
  UtensilsCrossed, 
  Package, 
  UserCircle,
  Banknote,
  PiggyBank,
  Wallet,
  Smartphone,
  Receipt,
  Star,
  DollarSign,
  Tag,
  Warehouse,
  Flame,
  CheckCircle2,
  XCircle,
  Clock,
  Megaphone
} from "lucide-react";
import {useOrdersStore} from "@/store/useOrdersStore";
import {useMenuStore} from "@/store/useMenuStore";
import {useInventoryStore} from "@/store/useInventoryStore";
import {useRecipesStore} from "@/store/useRecipesStore";
import {useAssembliesStore} from "@/store/useAssembliesStore";
import {useHistoryStore} from "@/store/useHistoryStore";
import {useMarketingStore} from "@/store/useMarketingStore";
import { computeAnalytics } from "@/lib/analytics";

type TabType = 'overview' | 'finance' | 'sales' | 'inventory' | 'workload';

export default function DashboardPage() {
  const [activeTab, setActiveTab] = useState<TabType>('overview');

  const { orders, fetchOrders, subscribeToOrders, unsubscribeFromOrders, isLoading: oLoading } = useOrdersStore();
  const { history, fetchHistory, isLoading: hLoading } = useHistoryStore();
  const { items: menuItems, fetchMenuItems, isLoading: mLoading } = useMenuStore();
  const { categories: inventoryCats, fetchInventory, isLoading: iLoading } = useInventoryStore();
  const { recipes, fetchRecipes, isLoading: rLoading } = useRecipesStore();
  const { assemblies, fetchAssemblies, isLoading: aLoading } = useAssembliesStore();
  const { campaigns, fetchCampaigns, isLoading: mcLoading } = useMarketingStore();

  useEffect(() => {
    fetchOrders();
    fetchHistory();
    fetchMenuItems();
    fetchInventory();
    fetchRecipes();
    fetchAssemblies();
    fetchCampaigns();

    subscribeToOrders();
    return () => {
      unsubscribeFromOrders();
    };
  }, [fetchOrders, fetchHistory, fetchMenuItems, fetchInventory, fetchRecipes, fetchAssemblies, fetchCampaigns, subscribeToOrders, unsubscribeFromOrders]);

  const loading = oLoading || hLoading || mLoading || iLoading || rLoading || aLoading || mcLoading;

  const analytics = useMemo(() => {
    if (loading) return null;
    const allOrders = [...orders, ...history];
    return computeAnalytics(allOrders, menuItems, inventoryCats, recipes, assemblies, campaigns);
  }, [orders, history, menuItems, inventoryCats, recipes, assemblies, campaigns, loading]);

  const today = new Date();

  const todayOrders = orders.filter(o => {
    const dateForCalculation = new Date(o.reservationDate || o.createdAt);
    return dateForCalculation.getFullYear() === today.getFullYear() &&
           dateForCalculation.getMonth() === today.getMonth() &&
           dateForCalculation.getDate() === today.getDate();
  });

  const revenueOrders = todayOrders.filter(o => o.status !== 'cancelled');

  const stats = {
    newOrders: orders.filter(o => o.status === 'new').length,
    todayOrders: todayOrders.length,
    revenue: revenueOrders.reduce((sum, o) => sum + o.totalAmount, 0),
    menuItemsCount: menuItems.filter(m => m.isActive).length,
    inventoryItemsCount: inventoryCats.reduce((sum, cat) => sum + cat.items.length, 0),
  };

  const recentOrders = orders.slice(0, 5);

  const tabs: { id: TabType; label: string; icon: React.ElementType }[] = [
    { id: 'overview', label: 'Обзор', icon: UserCircle },
    { id: 'finance', label: 'Финансы', icon: Banknote },
    { id: 'sales', label: 'Продажи', icon: UtensilsCrossed },
    { id: 'inventory', label: 'Склад', icon: Warehouse },
    { id: 'workload', label: 'Нагрузка', icon: Flame },
  ];

  return (
    <div className="space-y-6 max-w-7xl">
      <div>
        <h1 className="text-3xl font-bold tracking-tight">Дашборд и Аналитика</h1>
        <p className="text-muted-foreground">Обзор ключевых показателей ресторана</p>
      </div>

      <div className="flex bg-[#141414] border border-white/5 rounded-2xl p-1 overflow-x-auto custom-scrollbar">
        {tabs.map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className={`flex items-center gap-2 px-6 py-3 rounded-xl font-medium transition-colors whitespace-nowrap ${
              activeTab === tab.id 
                ? 'bg-[#FF6B00] text-white shadow-lg shadow-orange-500/20' 
                : 'text-neutral-400 hover:text-white hover:bg-white/5'
            }`}
          >
            <tab.icon className="w-4 h-4" />
            {tab.label}
          </button>
        ))}
      </div>

      {loading ? (
        <div className="flex h-64 items-center justify-center bg-[#141414] rounded-3xl border border-white/5">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-[#FF6B00]"></div>
        </div>
      ) : (
        <div className="animate-in fade-in duration-300">

          {/* TAB: Обзор */}
          {activeTab === 'overview' && (
            <div className="space-y-6">
              <div className="grid gap-4 md:grid-cols-3">
                <StatCard 
                  title="Новых заказов" 
                  value={stats.newOrders.toString()} 
                  subtitle="требуют внимания"
                  icon={<PlusCircle className="h-5 w-5 text-white" />}
                  gradient="bg-gradient-to-br from-orange-500 to-orange-400"
                  borderColor="border-orange-500/20"
                  valueColor="text-orange-500"
                />
                <StatCard 
                  title="Сегодня" 
                  value={stats.todayOrders.toString()} 
                  subtitle="заказов"
                  icon={<CalendarDays className="h-5 w-5 text-white" />}
                  gradient="bg-gradient-to-br from-amber-500 to-amber-400"
                  borderColor="border-amber-500/20"
                  valueColor="text-amber-500"
                />
                <StatCard 
                  title="Выручка" 
                  value={`${stats.revenue.toFixed(0)} ₪`} 
                  subtitle="за сегодня"
                  icon={<TrendingUp className="h-5 w-5 text-white" />}
                  gradient="bg-gradient-to-br from-emerald-500 to-teal-500"
                  borderColor="border-emerald-500/20"
                  valueColor="text-emerald-500"
                />
              </div>

              <div className="grid gap-4 md:grid-cols-2">
                <PillCard 
                  title="Блюд в меню"
                  value={stats.menuItemsCount.toString()}
                  subtitle="всего активных"
                  icon={<UtensilsCrossed className="h-6 w-6 text-indigo-500" />}
                  iconBg="bg-indigo-500/10"
                  valueColor="text-indigo-500"
                />
                <PillCard 
                  title="На складе"
                  value={stats.inventoryItemsCount.toString()}
                  subtitle="позиций"
                  icon={<Package className="h-6 w-6 text-cyan-500" />}
                  iconBg="bg-cyan-500/10"
                  valueColor="text-cyan-500"
                />
              </div>

              <div className="pt-4">
                <div className="flex items-center gap-3 mb-4">
                  <div className="h-5 w-1 rounded-full bg-orange-500"></div>
                  <h2 className="text-xl font-bold">Последние заказы</h2>
                </div>

                <div className="rounded-2xl border border-white/5 bg-[#141414] overflow-hidden">
                  {recentOrders.length === 0 ? (
                    <div className="p-8 text-center text-muted-foreground">Нет заказов</div>
                  ) : (
                    recentOrders.map((o, i) => (
                      <div key={o.id} className="group">
                        {i > 0 && <div className="h-px w-full bg-white/5"></div>}
                        <div className="flex items-center gap-4 p-4 hover:bg-white/5 transition-colors">
                          <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-orange-500/10">
                            <UserCircle className="h-5 w-5 text-orange-500" />
                          </div>
                          <div className="flex-1">
                            <p className="text-sm font-semibold">{o.customerName || 'Неизвестный'}</p>
                            <p className="text-xs text-muted-foreground">{o.customerPhone || 'Нет телефона'}</p>
                          </div>
                          <div className="text-right">
                            <p className="text-sm font-bold text-orange-500">{o.totalAmount || 0} ₪</p>
                            <div className="mt-1 inline-flex items-center rounded-full bg-orange-500/10 px-2.5 py-0.5 text-[10px] font-semibold text-orange-500 uppercase">
                              {o.status || 'NEW'}
                            </div>
                          </div>
                        </div>
                      </div>
                    ))
                  )}
                </div>
              </div>
            </div>
          )}

          {/* TAB: Финансы */}
          {activeTab === 'finance' && analytics && (
            <div className="space-y-6">
              <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
                <FinanceCard title="Общая Выручка" value={`${analytics.totalRevenue.toFixed(2)} ₪`} icon={<Wallet />} color="text-green-500" bg="bg-green-500/10" />
                <FinanceCard title="Чистая Прибыль" value={`${analytics.netProfit.toFixed(2)} ₪`} icon={<PiggyBank />} color="text-blue-500" bg="bg-blue-500/10" />
                <FinanceCard title="Оплата Наличными" value={`${analytics.cashRevenue.toFixed(2)} ₪`} icon={<Banknote />} color="text-orange-500" bg="bg-orange-500/10" />
                <FinanceCard title="Оплата Bit" value={`${analytics.bitRevenue.toFixed(2)} ₪`} icon={<Smartphone />} color="text-purple-500" bg="bg-purple-500/10" />
                <FinanceCard 
                  title="Средний Чек" 
                  value={analytics.completedOrdersCount > 0 ? `${(analytics.totalRevenue / analytics.completedOrdersCount).toFixed(2)} ₪` : '0 ₪'} 
                  icon={<Receipt />} 
                  color="text-teal-500" 
                  bg="bg-teal-500/10" 
                />
              </div>

              <div className="py-2">
                <h2 className="text-xl font-bold mb-4">Маркетинг</h2>
                <div className="grid gap-4 md:grid-cols-2">
                  <FinanceCard 
                    title="Активный Бюджет Рекламы" 
                    value={`${analytics.marketingBudgetTotal.toFixed(2)} ₪`} 
                    icon={<Megaphone className="w-6 h-6" />} 
                    color="text-pink-500" 
                    bg="bg-pink-500/10" 
                  />
                  <FinanceCard 
                    title="Потрачено на маркетинг" 
                    value={`${analytics.marketingSpentTotal.toFixed(2)} ₪`} 
                    icon={<Wallet className="w-6 h-6" />} 
                    color="text-red-500" 
                    bg="bg-red-500/10" 
                  />
                </div>
              </div>
            </div>
          )}

          {/* TAB: Продажи */}
          {activeTab === 'sales' && analytics && (
            <div className="space-y-6">
              <div className="grid md:grid-cols-2 gap-6">
                <ListCard title="ТОП-10 Продаваемых блюд (в шт.)" items={analytics.topSellingDishes} icon={<Star className="text-white w-4 h-4"/>} iconBg="bg-orange-500"
                  renderValue={(i: { count: number; name: string }) => `${i.count} шт.`}
                  renderKey={(i: { count: number; name: string }) => i.name}
                />
                <ListCard title="ТОП-10 Прибыльных блюд (маржа)" items={analytics.topProfitableDishes} icon={<DollarSign className="text-white w-4 h-4"/>} iconBg="bg-green-500"
                  renderValue={(i: { profit: number; name: string }) => `${i.profit.toFixed(2)} ₪`}
                  valueColor="text-green-500"
                  renderKey={(i: { profit: number; name: string }) => i.name}
                />
              </div>
            </div>
          )}

          {/* TAB: Склад */}
          {activeTab === 'inventory' && analytics && (
            <div className="space-y-6">
              <FinanceCard title="Капитал на Складе (Итого)" value={`${analytics.totalInventoryCapital.toFixed(2)} ₪`} icon={<Warehouse />} color="text-slate-400" bg="bg-slate-500/10" className="md:w-1/2"/>

              <div className="grid md:grid-cols-2 gap-6">
                <ListCard title="Капитал по Колонкам (Инвентарь)" items={Object.entries(analytics.inventoryCapitalByCategory).map(([k,v]) => ({name: k, cap: v}))} icon={<Tag className="text-slate-400 w-4 h-4"/>} iconBg="bg-slate-500/20"
                  renderValue={(i: { cap: number; name: string }) => `${i.cap.toFixed(2)} ₪`}
                  valueColor="text-blue-400"
                  renderKey={(i: { cap: number; name: string }) => i.name}
                />
                <ListCard title="ТОП-10 Расходов на ингредиенты (от заказов)" items={analytics.mostUsedIngredients} icon={<Flame className="text-white w-4 h-4"/>} iconBg="bg-slate-700"
                  renderValue={(i: { cost: number; name: string }) => `-${i.cost.toFixed(2)} ₪`}
                  valueColor="text-red-500"
                  renderKey={(i: { cost: number; name: string }) => i.name}
                />
              </div>
            </div>
          )}

          {/* TAB: Нагрузка */}
          {activeTab === 'workload' && analytics && (
            <div className="space-y-6">
              <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
                 <FinanceCard title="Успешные Заказы" value={`${analytics.completedOrdersCount} шт.`} icon={<CheckCircle2 />} color="text-green-500" bg="bg-green-500/10" />
                 <FinanceCard title="Отмененные Заказы" value={`${analytics.cancelledOrdersCount} шт. (${analytics.completedOrdersCount + analytics.cancelledOrdersCount > 0 ? (analytics.cancelledOrdersCount/(analytics.completedOrdersCount+analytics.cancelledOrdersCount)*100).toFixed(1) : 0}%)`} icon={<XCircle />} color="text-red-500" bg="bg-red-500/10" />
              </div>
              <div className="grid md:grid-cols-2 gap-6">
                <ListCard title="Пиковые Часы Нагрузки (ТОП)" items={analytics.ordersByHour.slice(0, 7)} icon={<Clock className="text-white w-4 h-4"/>} iconBg="bg-blue-600"
                    renderValue={(i: { count: number; hour: string }) => `${i.count} заказов`}
                    renderKey={(i: { count: number; hour: string }) => i.hour}
                  />
              </div>
            </div>
          )}

        </div>
      )}
    </div>
  );
}

// Subcomponents

function StatCard({ title, value, subtitle, icon, gradient, borderColor, valueColor }: { title: string; value: string; subtitle: string; icon: React.ReactNode; gradient: string; borderColor: string; valueColor: string }) {
  return (
    <div className={`rounded-2xl border ${borderColor} bg-[#141414] p-5 shadow-sm`}>
      <div className={`flex h-10 w-10 items-center justify-center rounded-xl ${gradient}`}>
        {icon}
      </div>
      <div className="mt-4">
        <h3 className={`text-3xl font-bold tracking-tight ${valueColor}`}>{value}</h3>
        <p className="mt-1 text-sm font-semibold">{title}</p>
        <p className="text-xs text-muted-foreground">{subtitle}</p>
      </div>
    </div>
  );
}

function PillCard({ title, value, subtitle, icon, iconBg, valueColor }: { title: string; value: string; subtitle: string; icon: React.ReactNode; iconBg: string; valueColor: string }) {
  return (
    <div className="flex items-center gap-4 rounded-2xl border border-white/5 bg-[#141414] p-5 shadow-sm">
      <div className={`flex h-12 w-12 items-center justify-center rounded-xl ${iconBg}`}>
        {icon}
      </div>
      <div>
        <h3 className={`text-2xl font-bold ${valueColor}`}>{value}</h3>
        <p className="text-sm font-semibold">{title}</p>
        <p className="text-xs text-muted-foreground">{subtitle}</p>
      </div>
    </div>
  );
}

function FinanceCard({ title, value, icon, color, bg, className = "" }: { title: string; value: string; icon: React.ReactNode; color: string; bg: string; className?: string }) {
  return (
    <div className={`flex items-center gap-4 p-6 rounded-2xl border border-white/5 bg-[#141414] ${className}`}>
      <div className={`w-12 h-12 rounded-full flex items-center justify-center ${bg} ${color}`}>
        {icon}
      </div>
      <div>
        <h3 className="text-sm font-medium text-neutral-400">{title}</h3>
        <p className="text-2xl font-extrabold text-white mt-1">{value || '0'}</p>
      </div>
    </div>
  );
}

function ListCard({ title, items, icon, iconBg, renderValue, renderKey, valueColor = "text-white" }: { title: string; items: any[]; icon: React.ReactNode; iconBg: string; renderValue: (i: any) => React.ReactNode; renderKey: (i: any) => React.ReactNode; valueColor?: string }) {
  return (
    <div className="bg-[#141414] border border-white/5 rounded-2xl overflow-hidden">
      <div className="px-6 py-4 border-b border-white/5">
        <h2 className="text-lg font-bold text-white">{title}</h2>
      </div>
      {items.length === 0 ? (
        <div className="p-6 text-center text-neutral-500">Нет данных</div>
      ) : (
        <div className="divide-y divide-white/5">
          {items.map((item: Record<string, unknown>, idx: number) => (
            <div key={idx} className="flex items-center justify-between p-4 hover:bg-white/5 transition">
              <div className="flex items-center gap-3">
                <div className={`w-8 h-8 rounded-full flex flex-shrink-0 items-center justify-center ${iconBg}`}>
                  {icon}
                </div>
                <span className="font-medium text-white">{renderKey(item)}</span>
              </div>
              <div className={`font-bold ${valueColor}`}>{renderValue(item)}</div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

"use client";

import { useEffect } from "react";
import {useMenuStore} from "@/store/useMenuStore";
import {useLandingSettingsStore} from "@/store/useLandingSettingsStore";
import StorefrontClientLocal from "@/components/StorefrontClientLocal";

export default function FrontPage() {
  const { items: menuItems, categories, fetchMenuItems, fetchCategories } = useMenuStore();
  const { settings, fetchSettings } = useLandingSettingsStore();

  useEffect(() => {
    fetchMenuItems();
    fetchCategories();
    fetchSettings();
  }, [fetchMenuItems, fetchCategories, fetchSettings]);

  // Transform MenuItems to match Local types
  const mappedCategories : any[] = categories.map(c => ({
    id: c.id,
    name: c.name,
    name_en: c.name,
    name_he: c.name,
    name_uk: c.name,
  }));

  const mappedItems : any[] = menuItems.map(m => ({
    id: m.id,
    name: m.name,
    name_en: m.name,
    name_he: m.name,
    name_uk: m.name,
    description: m.description,
    description_en: m.description,
    description_he: m.description,
    description_uk: m.description,
    image_url: m.image,
    price: m.price,
    stock: m.stock,
    is_active: m.isActive,
    is_poll: m.isPoll,
    category_id: m.categoryId,
  }));

  return (
    <div className="w-full h-full relative -m-6 flex flex-col overflow-y-auto bg-black text-white">
      <StorefrontClientLocal 
        menuItems={mappedItems} 
        landingSettings={settings || {}} 
        categories={mappedCategories} 
      />
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import {useLandingSettingsStore} from "@/store/useLandingSettingsStore";
import { Loader2, Save, Globe } from "lucide-react";

export default function LandingSettingsPage() {
  const { settings, isLoading, fetchSettings, updateSettings } = useLandingSettingsStore();
  const [isSaving, setIsSaving] = useState(false);

  // Local form state
  const [formData, setFormData] = useState<Record<string, any>>({});

  useEffect(() => {
    fetchSettings();
  }, [fetchSettings]);

  useEffect(() => {
    if (settings) {
      setFormData(settings);
    }
  }, [settings]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value, type } = e.target;
    if (type === "checkbox") {
      const checked = (e.target as HTMLInputElement).checked;
      setFormData((prev: Record<string, unknown>) => ({ ...prev, [name]: checked }));
    } else {
      setFormData((prev: Record<string, unknown>) => ({ ...prev, [name]: value }));
    }
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSaving(true);
    try {
      await updateSettings(formData);
      alert("Настройки успешно сохранены!");
    } catch (err: unknown) {
      alert("Ошибка при сохранении: " + (err as Error).message);
    } finally {
      setIsSaving(false);
    }
  };

  if (isLoading && !settings) {
    return (
      <div className="flex justify-center items-center h-40">
        <Loader2 className="w-8 h-8 animate-spin text-orange-500" />
      </div>
    );
  }

  if (!settings) {
    return <div className="text-center text-muted-foreground mt-10">Настройки лендинга не найдены в базе.</div>;
  }

  return (
    <div className="space-y-6 max-w-4xl">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Настройки Лендинга</h1>
          <p className="text-muted-foreground">Управление главным экраном, контактами и режимами приема заказов</p>
        </div>
        <button
          onClick={handleSave}
          disabled={isSaving}
          className="bg-orange-600 hover:bg-orange-500 text-white px-4 py-2 rounded-xl flex items-center gap-2 font-medium transition disabled:opacity-50"
        >
          {isSaving ? <Loader2 className="w-5 h-5 animate-spin" /> : <Save className="w-5 h-5" />}
          Сохранить
        </button>
      </div>

      <form onSubmit={handleSave} className="space-y-8">
        {/* Главный экран */}
        <div className="bg-[#141414] border border-white/10 rounded-2xl p-6 shadow-sm">
          <div className="flex items-center gap-2 mb-6 text-orange-500">
            <Globe className="w-6 h-6" />
            <h2 className="text-xl font-semibold text-white">Главный экран</h2>
          </div>

          <div className="grid grid-cols-1 gap-4">
            <div>
              <label className="block text-sm font-medium text-neutral-400 mb-1">Главный заголовок (RU)</label>
              <input type="text" name="hero_title" value={formData.hero_title || ""} onChange={handleChange} className="w-full bg-[#1A1A1A] border border-white/10 rounded-xl px-4 py-2.5 text-white focus:outline-none focus:border-orange-500" />
            </div>
            <div>
              <label className="block text-sm font-medium text-neutral-400 mb-1">Подзаголовок (RU)</label>
              <input type="text" name="hero_subtitle" value={formData.hero_subtitle || ""} onChange={handleChange} className="w-full bg-[#1A1A1A] border border-white/10 rounded-xl px-4 py-2.5 text-white focus:outline-none focus:border-orange-500" />
            </div>
            <div>
              <label className="block text-sm font-medium text-neutral-400 mb-1">О нас (RU)</label>
              <textarea name="about_text" value={formData.about_text || ""} onChange={handleChange} rows={4} className="w-full bg-[#1A1A1A] border border-white/10 rounded-xl px-4 py-2.5 text-white focus:outline-none focus:border-orange-500 resize-none" />
            </div>
          </div>
        </div>

        {/* Контакты */}
        <div className="bg-[#141414] border border-white/10 rounded-2xl p-6 shadow-sm">
          <h2 className="text-xl font-semibold text-white mb-6">Контакты и Адрес</h2>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-neutral-400 mb-1">Телефон</label>
              <input type="text" name="contact_phone" value={formData.contact_phone || ""} onChange={handleChange} className="w-full bg-[#1A1A1A] border border-white/10 rounded-xl px-4 py-2.5 text-white focus:outline-none focus:border-orange-500" />
            </div>
            <div>
              <label className="block text-sm font-medium text-neutral-400 mb-1">Email</label>
              <input type="text" name="contact_email" value={formData.contact_email || ""} onChange={handleChange} className="w-full bg-[#1A1A1A] border border-white/10 rounded-xl px-4 py-2.5 text-white focus:outline-none focus:border-orange-500" />
            </div>
            <div>
              <label className="block text-sm font-medium text-neutral-400 mb-1">Адрес</label>
              <input type="text" name="address" value={formData.address || ""} onChange={handleChange} className="w-full bg-[#1A1A1A] border border-white/10 rounded-xl px-4 py-2.5 text-white focus:outline-none focus:border-orange-500" />
            </div>
            <div>
              <label className="block text-sm font-medium text-neutral-400 mb-1">Часы работы</label>
              <input type="text" name="working_hours" value={formData.working_hours || ""} onChange={handleChange} className="w-full bg-[#1A1A1A] border border-white/10 rounded-xl px-4 py-2.5 text-white focus:outline-none focus:border-orange-500" />
            </div>
          </div>
        </div>
        {/* Режимы заказов */}
        <div className="bg-[#141414] border border-white/10 rounded-2xl p-6 shadow-sm">
          <h2 className="text-xl font-semibold text-white mb-6">Логистика и доставка</h2>
          <div className="flex flex-col gap-4">
            <label className="flex items-center gap-3 cursor-pointer">
              <input 
                type="checkbox" 
                name="is_delivery_enabled" 
                checked={!!formData.is_delivery_enabled} 
                onChange={(e) => setFormData((prev: Record<string, unknown>) => ({ ...prev, is_delivery_enabled: e.target.checked }))} 
                className="w-5 h-5 accent-orange-500 rounded border-white/10" 
              />
              <div className="flex flex-col">
                <span className="text-white font-medium">Включить Доставку</span>
                <span className="text-neutral-500 text-xs">Разрешить клиентам выбирать доставку</span>
              </div>
            </label>
            <label className="flex items-center gap-3 cursor-pointer">
              <input 
                type="checkbox" 
                name="is_pickup_enabled" 
                checked={!!formData.is_pickup_enabled} 
                onChange={(e) => setFormData((prev: Record<string, unknown>) => ({ ...prev, is_pickup_enabled: e.target.checked }))} 
                className="w-5 h-5 accent-orange-500 rounded border-white/10" 
              />
              <div className="flex flex-col">
                <span className="text-white font-medium">Включить Самовывоз</span>
                <span className="text-neutral-500 text-xs">Разрешить клиентам забирать заказ самим</span>
              </div>
            </label>
            <label className="flex items-center gap-3 cursor-pointer">
              <input 
                type="checkbox" 
                name="is_preorder_mode" 
                checked={!!formData.is_preorder_mode} 
                onChange={(e) => setFormData((prev: Record<string, unknown>) => ({ ...prev, is_preorder_mode: e.target.checked }))} 
                className="w-5 h-5 accent-orange-500 rounded border-white/10" 
              />
              <div className="flex flex-col">
                <span className="text-white font-medium">Режим Только Предзаказ</span>
                <span className="text-neutral-500 text-xs">Отключить заказы на 'сегодня', разрешить только со следующего дня</span>
              </div>
            </label>
          </div>
        </div>

      </form>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { format } from "date-fns";
import { 
  Archive, 
  Edit2, 
  Trash2, 
  Clock, 
  RotateCw,
  Receipt,
  Users
} from "lucide-react";
import Link from "next/link";
import { OrderEditModal } from "./components/OrderEditModal";
import {useOrdersStore} from "@/store/useOrdersStore"
import { useTranslationsStore } from "@/store/useTranslationsStore";
import { OrderStatus, Order } from "@borsch/types";;
import { ConfirmModal } from "@/components/ConfirmModal";

const STATUS_CONFIG: Record<OrderStatus, { label: string, colorClass: string, hex: string }> = {
  new: { label: 'Новый', colorClass: 'text-orange-500 bg-orange-500', hex: '#FF6B00' },
  preparing: { label: 'Готовится', colorClass: 'text-amber-500 bg-amber-500', hex: '#FFC107' },
  ready: { label: 'Готов', colorClass: 'text-[#00C853] bg-[#00C853]', hex: '#00C853' },
  delivering: { label: 'У курьера', colorClass: 'text-blue-500 bg-blue-500', hex: '#3B82F6' },
  completed: { label: 'Выполнен', colorClass: 'text-gray-500 bg-gray-500', hex: '#6B7280' },
  cancelled: { label: 'Отменён', colorClass: 'text-red-500 bg-red-500', hex: '#EF4444' },
};

export default function OrdersPage() {
  const { orders, isLoading, fetchOrders, subscribeToOrders, unsubscribeFromOrders } = useOrdersStore();
  const [editingOrder, setEditingOrder] = useState<Order | null>(null);
  const [confirmDelete, setConfirmDelete] = useState<string | null>(null);
  const [confirmArchive, setConfirmArchive] = useState<string | null>(null);

  useEffect(() => {
    fetchOrders();
    subscribeToOrders();
    return () => unsubscribeFromOrders();
  }, [fetchOrders, subscribeToOrders, unsubscribeFromOrders]);

  // Group orders by status
  const groupedOrders = (Object.keys(STATUS_CONFIG) as OrderStatus[]).reduce((acc, status) => {
    acc[status] = orders.filter(o => o.status === status);
    return acc;
  }, {} as Record<OrderStatus, Order[]>);

  return (
    <div className="flex h-full flex-col">
      {/* Header / Tabs */}
      <div className="flex items-center justify-between pb-4 border-b border-white/10 mb-6">
        <h1 className="text-2xl font-bold tracking-tight">Управление</h1>
      </div>

      <div className="flex-1 overflow-auto">
          {isLoading && orders.length === 0 ? (
            <div className="flex h-64 flex-col items-center justify-center">
              <div className="w-8 h-8 rounded-full border-2 border-orange-500 border-t-transparent animate-spin mb-4" />
              <p className="text-xl font-semibold text-gray-500">Загрузка...</p>
            </div>
          ) : orders.length === 0 ? (
            <div className="flex h-64 flex-col items-center justify-center">
              <Receipt className="h-16 w-16 text-[#2A2A2A] mb-4" />
              <p className="text-xl font-semibold text-gray-500">Заказов пока нет</p>
              <p className="text-sm text-gray-600">Новые заказы появятся здесь</p>
            </div>
          ) : (
            <div className="pb-20">
              {(Object.keys(STATUS_CONFIG) as OrderStatus[]).map((status) => {
                const group = groupedOrders[status];
                if (group.length === 0) return null;

                const config = STATUS_CONFIG[status];

                return (
                  <div key={status} className="mb-8">
                    {/* Status Header */}
                    <div className="flex items-center gap-3 mb-4">
                      <div className="w-2.5 h-2.5 rounded-full shadow-[0_0_6px_rgba(0,0,0,0.5)]" style={{ backgroundColor: config.hex, boxShadow: `0 0 6px ${config.hex}80` }}></div>
                      <h2 className="text-lg font-bold">{config.label}</h2>
                      <div className="px-2.5 py-0.5 rounded-full text-xs font-bold" style={{ backgroundColor: `${config.hex}26`, color: config.hex }}>
                        {group.length}
                      </div>
                    </div>

                    {/* Order Grid */}
                    <div className="grid grid-cols-[repeat(auto-fill,minmax(450px,1fr))] gap-6">
                      {group.map(order => (
                        <OrderCard 
                          key={order.id} 
                          order={order} 
                          onEdit={() => setEditingOrder(order)} 
                          onArchive={() => setConfirmArchive(order.id)}
                          onDelete={() => setConfirmDelete(order.id)}
                        />
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>
          )}

          {/* Floating Action Button Alternative (Bottom right fixed) */}
          <button 
            onClick={() => fetchOrders()}
            className="fixed bottom-8 right-8 h-12 w-12 rounded-2xl bg-[#1A1A1A] border border-white/10 flex items-center justify-center shadow-lg hover:bg-white/5 transition-colors text-white"
          >
            <RotateCw className="w-5 h-5" />
          </button>
        </div>

        <OrderEditModal 
          isOpen={editingOrder !== null} 
          onClose={() => setEditingOrder(null)} 
          order={editingOrder} 
        />

        {confirmDelete && (
          <ConfirmModal
            title="Удалить заказ?"
            message="Точно удалить этот заказ? Это действие необратимо."
            onConfirm={() => useOrdersStore.getState().deleteOrder(confirmDelete)}
            onCancel={() => setConfirmDelete(null)}
          />
        )}

        {confirmArchive && (
          <ConfirmModal
            title="В архив?"
            message="Завершить заказ и убрать в архив?"
            onConfirm={() => useOrdersStore.getState().archiveOrder(confirmArchive)}
            onCancel={() => setConfirmArchive(null)}
          />
        )}
    </div>
  );
}

function OrderCard({ order, onEdit, onArchive, onDelete }: { order: Order; onEdit: () => void; onArchive: () => void; onDelete: () => void }) {
  const { items: tItems, adminLang, t } = useTranslationsStore();
  const c = STATUS_CONFIG[order.status];
  const dateStr = format(new Date(order.reservationDate || order.createdAt), "dd.MM HH:mm");
  const pickupStr = order.reservationDate ? format(new Date(order.reservationDate), "dd.MM HH:mm") : '—';

  const getItemName = (it: any) => {
    if (it.menuItemId === 'delivery') return t('delivery', 'Доставка');
    if (it.menuItemName.includes('Хлеб') || it.menuItemName.includes('Bread') || it.menuItemName.includes('לחם')) return t('bread', '🍞 Хлеб');
    if (it.menuItemName.includes('Приборы') || it.menuItemName.includes('Cutlery') || it.menuItemName.includes('סכו"ם')) return t('cutlery', '🍴 Приборы');

    if (it.menuItemId) {
      const tr = tItems.find(i => i.id === it.menuItemId && i.type === 'menu');
      if (tr) {
        if (adminLang === 'ru' && tr.originalName) return tr.originalName;
        if (adminLang === 'en' && tr.nameEn) return tr.nameEn;
        if (adminLang === 'he' && tr.nameHe) return tr.nameHe;
        if (adminLang === 'uk' && tr.nameUk) return tr.nameUk;
      }
    }
    return it.menuItemName;
  };

  return (
    <div className="flex flex-col bg-[#141414] rounded-[18px] border h-full" style={{ borderColor: `${c.hex}38` }}>
      {/* Header Stripe */}
      <div className="flex items-center px-4 py-3 rounded-t-[17px] gap-2 overflow-hidden" style={{ backgroundColor: `${c.hex}14` }}>
        <div className="w-2.5 h-2.5 rounded-full shrink-0" style={{ backgroundColor: c.hex, boxShadow: `0 0 4px ${c.hex}99` }}></div>
        <span className="text-sm font-bold shrink-0" style={{ color: c.hex }}>{c.label}</span>

        <div className="flex-1 min-w-0" /> {/* Spacer */}

        <div className="flex items-center gap-3 shrink-0">
          <span className="text-xs text-white/50 hidden sm:inline-block">{order.reservationDate ? `📅 ${dateStr}` : dateStr}</span>
          <button 
            onClick={onArchive}
            className="text-amber-500 hover:text-amber-400 transition-colors"
          >
            <Archive className="w-[18px] h-[18px]" />
          </button>
            <button onClick={onEdit} className="text-white/60 hover:text-white transition-colors">
              <Edit2 className="w-[18px] h-[18px]" />
            </button>
            <button 
              onClick={onDelete}
              className="text-red-500 hover:text-red-400 transition-colors"
            >
              <Trash2 className="w-[18px] h-[18px]" />
            </button>
          </div>
        </div>

      {/* Body */}
      <div className="flex flex-col flex-1 p-4 pt-3.5">
        {/* Customer Info */}
        <div className="mb-3 border-b border-white/5 pb-3">
          <h3 className="font-bold text-lg text-white break-words leading-tight">{order.customerName}</h3>
          <div className="flex items-center mt-2 gap-3 flex-wrap">
            <span className="text-sm font-medium text-white/60">{order.customerPhone || '—'}</span>
            <span className="px-2 py-1 rounded bg-white/10 text-xs text-amber-500 font-bold border border-amber-500/20">
              {order.paymentMethod === 'bit' ? '💳 Bit' : '💵 Наличные'}
            </span>
          </div>
        </div>

        {/* Items List */}
        <div className="flex-1 space-y-2 mb-4">
          {order.items.map(it => (
            <div key={it.id} className="flex items-start text-[14px] leading-snug">
              <span className="font-bold text-orange-500 mr-2 shrink-0">{it.quantity}x</span>
              <span className="text-white break-words">{getItemName(it)}</span>
            </div>
          ))}
        </div>

        {/* Footer info */}
        <div className="flex items-center justify-between mt-auto">
          <div className="flex items-center gap-1.5 text-white/40">
            <Clock className="w-[11px] h-[11px]" />
            <span className="text-[11px]">{pickupStr}</span>
          </div>
          <span className="font-extrabold text-lg text-orange-500">{order.totalAmount} ₪</span>
        </div>
      </div>

      {/* Status Dropdown */}
      <div className="mx-3 mb-3 mt-1 relative">
        <select 
          className="w-full appearance-none bg-white/5 border border-white/10 rounded-[10px] py-1.5 px-3 text-[13px] font-medium text-white outline-none focus:border-white/20 transition-colors"
          value={order.status}
          onChange={(e) => useOrdersStore.getState().updateOrderStatus(order.id, e.target.value as OrderStatus)}
        >
          {Object.entries(STATUS_CONFIG).map(([val, conf]) => (
            <option key={val} value={val} className="bg-[#1C1C1C] text-white py-2">
              {conf.label}
            </option>
          ))}
        </select>
        <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none" style={{ color: c.hex }}>
          ▼
        </div>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { Plus, BookOpen, Edit3, Trash2 } from "lucide-react";
import { useRecipesStore } from "@/store/useRecipesStore";
import { Recipe } from "@borsch/types";
import { useInventoryStore } from "@/store/useInventoryStore";
import { ConfirmModal } from "@/components/ConfirmModal";
import { RecipeEditModal } from "./components/RecipeEditModal";

export default function RecipesPage() {
  const { recipes, isLoading, fetchRecipes, subscribeToRecipes, unsubscribeFromRecipes, addRecipe, updateRecipe, deleteRecipe } = useRecipesStore();
  const { categories, fetchInventory } = useInventoryStore();

  const [isModalOpen, setModalOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  const [name, setName] = useState("");
  const [portions, setPortions] = useState(1);
  const [ingredients, setIngredients] = useState<{ inventoryItemId: string, quantity: number }[]>([]);
  const [confirmDelete, setConfirmDelete] = useState<{ id: string, name: string } | null>(null);

  useEffect(() => {
    fetchRecipes();
    fetchInventory();
    subscribeToRecipes();
    return () => unsubscribeFromRecipes();
  }, [fetchRecipes, subscribeToRecipes, unsubscribeFromRecipes, fetchInventory]);

  const openAddModal = () => {
    setEditingId(null);
    setName("");
    setPortions(1);
    setIngredients([]);
    setModalOpen(true);
  };

  const openEditModal = (recipe: Recipe) => {
    setEditingId(recipe.id);
    setName(recipe.name);
    setPortions(recipe.portions);
    setIngredients(recipe.ingredients.map((ing: any) => ({ inventoryItemId: ing.inventoryItemId, quantity: ing.quantity })));
    setModalOpen(true);
  };

  const handleSave = async (id: string | null, newName: string, newPortions: number, newIngredients: { inventoryItemId: string, quantity: number }[]) => {
    try {
      if (id) {
        await updateRecipe(id, newName, newPortions, newIngredients);
      } else {
        await addRecipe(newName, newPortions, newIngredients);
      }
      setModalOpen(false);
    } catch (_e) {
      // Error handled by store alert
    }
  };

  const handleDelete = async (id: string, rName: string) => {
    setConfirmDelete({ id, name: rName });
  };

  const allInventoryItems = categories.flatMap(c => c.items);
  const availableInventoryItems = categories.filter(c => c.isVisibleInRecipe).flatMap(c => c.items);

  return (
    <div className="flex h-full flex-col">
      <div className="flex items-center justify-between pb-4 border-b border-white/10 mb-6 flex-shrink-0">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">Рецепты</h1>
          <p className="text-sm text-muted-foreground mt-1">ТТК и калькуляция блюд</p>
        </div>
        <button 
          onClick={openAddModal}
          className="flex items-center gap-2 px-4 py-2 rounded-lg bg-orange-500 hover:bg-orange-600 text-white text-sm font-bold transition-colors"
        >
          <Plus className="w-4 h-4" />
          Создать
        </button>
      </div>

      <div className="flex-1 overflow-auto pb-10">
        {isLoading && recipes.length === 0 ? (
          <div className="flex h-64 flex-col items-center justify-center w-full">
            <div className="w-8 h-8 rounded-full border-2 border-orange-500 border-t-transparent animate-spin mb-4" />
            <p className="text-xl font-semibold text-gray-500">Загрузка рецептов...</p>
          </div>
        ) : recipes.length === 0 ? (
          <div className="flex h-64 flex-col items-center justify-center w-full">
            <BookOpen className="h-16 w-16 text-[#2A2A2A] mb-4" />
            <p className="text-xl font-semibold text-gray-500">Рецептов пока нет</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {recipes.map(recipe => (
              <RecipeCard key={recipe.id} recipe={recipe} onEdit={() => openEditModal(recipe)} onDelete={() => handleDelete(recipe.id, recipe.name)} />
            ))}
          </div>
        )}
      </div>

      <RecipeEditModal 
        isOpen={isModalOpen}
        onClose={() => setModalOpen(false)}
        recipeId={editingId}
        initialName={name}
        initialPortions={portions}
        initialIngredients={ingredients}
        allInventoryItems={allInventoryItems}
        availableInventoryItems={availableInventoryItems}
        onSave={handleSave}
      />

      {confirmDelete && (
        <ConfirmModal
          title="Удалить рецепт?"
          message={`Точно удалить рецепт "${confirmDelete.name}"? Это действие необратимо.`}
          onConfirm={() => deleteRecipe(confirmDelete.id)}
          onCancel={() => setConfirmDelete(null)}
        />
      )}
    </div>
  );
}

function RecipeCard({ recipe, onEdit, onDelete }: { recipe: Recipe, onEdit: () => void, onDelete: () => void }) {
  const totalCost = recipe.ingredients.reduce((sum: number, ing: any) => {
    const price = ing.inventoryItem?.price || 0;
    const yieldFactor = ing.inventoryItem?.yieldPerUnit || 1;
    return sum + (ing.quantity * (price / yieldFactor));
  }, 0);

  const costPerPortion = recipe.portions > 0 ? totalCost / recipe.portions : 0;

  return (
    <div className="flex flex-col bg-[#141414] rounded-2xl border border-white/10 overflow-hidden hover:border-white/20 transition-colors">
      <div className="flex items-center px-4 py-3.5 bg-orange-500/10 border-b border-orange-500/10">
        <BookOpen className="w-5 h-5 text-orange-500 mr-3 shrink-0" />
        <h3 className="font-bold text-base flex-1 truncate">{recipe.name}</h3>
        <div className="flex items-center gap-2 shrink-0">
          <button onClick={onEdit} className="text-orange-500 hover:text-orange-400 transition-colors w-7 h-7 flex items-center justify-center rounded-lg bg-white/5">
            <Edit3 className="w-4 h-4" />
          </button>
          <button onClick={onDelete} className="text-red-500 hover:text-red-400 transition-colors w-7 h-7 flex items-center justify-center rounded-lg bg-white/5">
            <Trash2 className="w-4 h-4" />
          </button>
        </div>
      </div>

      <div className="flex flex-col flex-1 p-4 pt-3">
        <span className="text-xs text-white/40 mb-2">Состав:</span>
        <div className="flex-1 space-y-1 overflow-y-auto max-h-[140px]">
          {recipe.ingredients.length === 0 ? (
            <span className="text-xs text-white/30">Нет ингредиентов</span>
          ) : (
            recipe.ingredients.map((ing: any) => (
              <div key={ing.id} className="flex justify-between items-center text-xs">
                <span className="text-white/80 truncate pr-2">{ing.inventoryItem?.name || '?'}</span>
                <span className="text-white/50 shrink-0">{ing.quantity} {ing.inventoryItem?.recipeUnit || ing.inventoryItem?.unit || ''}</span>
              </div>
            ))
          )}
        </div>
      </div>

      <div className="px-4 py-3 border-t border-white/5 flex justify-between items-center">
        <span className="text-xs text-white/40">{recipe.portions} порц.</span>
        <div className="flex flex-col items-end">
          <span className="text-orange-500 font-bold text-sm">{costPerPortion.toFixed(2)} ₪/порц.</span>
          <span className="text-white/40 text-[10px]">Итого: {totalCost.toFixed(2)} ₪</span>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { Plus, Store, Clock, Phone, MapPin, Edit2 } from "lucide-react";
import { useRouter } from "next/navigation";

import {useSuppliersStore} from "@/store/useSuppliersStore"
import { Supplier } from "@borsch/types";;
import { SupplierEditModal } from "./components/SupplierEditModal";
import { SupplierDetails } from "./components/SupplierDetails";

export default function SuppliersPage() {
  const { suppliers, isLoading, fetchSuppliers, subscribeToSuppliers, unsubscribeFromSuppliers } = useSuppliersStore();
  const [editingSupplier, setEditingSupplier] = useState<{isOpen: boolean, supplier: Supplier | null}>({isOpen: false, supplier: null});
  const [selectedSupplierId, setSelectedSupplierId] = useState<string | null>(null);

  useEffect(() => {
    fetchSuppliers();
    subscribeToSuppliers();
    return () => unsubscribeFromSuppliers();
  }, [fetchSuppliers, subscribeToSuppliers, unsubscribeFromSuppliers]);

  if (selectedSupplierId) {
    return <SupplierDetails id={selectedSupplierId} onBack={() => setSelectedSupplierId(null)} />;
  }

  return (
    <div className="flex h-full flex-col">
      <div className="flex items-center justify-between pb-4 border-b border-white/10 mb-6 flex-shrink-0">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">Поставщики</h1>
          <p className="text-sm text-muted-foreground mt-1">База контактов</p>
        </div>
        <button 
          onClick={() => setEditingSupplier({isOpen: true, supplier: null})}
          className="flex items-center gap-2 px-4 py-2 rounded-lg bg-orange-500 hover:bg-orange-600 text-white text-sm font-bold transition-colors"
        >
          <Plus className="w-4 h-4" />
          Поставщик
        </button>
      </div>

      <div className="flex-1 overflow-y-auto pb-10">
        {isLoading && suppliers.length === 0 ? (
          <div className="flex h-64 flex-col items-center justify-center w-full">
            <div className="w-8 h-8 rounded-full border-2 border-orange-500 border-t-transparent animate-spin mb-4" />
            <p className="text-xl font-semibold text-gray-500">Загрузка...</p>
          </div>
        ) : suppliers.length === 0 ? (
          <div className="flex h-64 flex-col items-center justify-center w-full">
            <Store className="h-16 w-16 text-[#2A2A2A] mb-4" />
            <p className="text-xl font-semibold text-gray-500">Нет поставщиков</p>
            <p className="text-sm text-gray-600 mt-2">Нажмите Добавить</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
            {suppliers.map(sup => (
              <div 
                key={sup.id} 
                onClick={() => setSelectedSupplierId(sup.id)}
