                     <div className="grid grid-cols-4 gap-2">
                       <input required value={street} onChange={(e) => setStreet(e.target.value)} type="text" placeholder="Улица *" className="col-span-2 bg-[#111111] text-white border border-white/10 px-4 py-3 rounded-xl focus:outline-none focus:border-[#FF6B00] transition" />
                       <input required value={house} onChange={(e) => setHouse(e.target.value.replace(/\D/g, ''))} type="text" placeholder="Дом *" className="col-span-1 min-w-0 bg-[#111111] text-white border border-white/10 px-3 py-3 rounded-xl focus:outline-none focus:border-[#FF6B00] transition text-center" />
                       <input value={apt} onChange={(e) => setApt(e.target.value.replace(/\D/g, ''))} type="text" placeholder="Кв." className="col-span-1 min-w-0 bg-[#111111] text-white border border-white/10 px-3 py-3 rounded-xl focus:outline-none focus:border-[#FF6B00] transition text-center" />
                     </div>
                  )}

                  <div className="flex gap-2">
                    <select 
                      required
                      value={reservationDateOffset}
                      onChange={(e) => setReservationDateOffset(parseInt(e.target.value, 10))}
                      className="w-full bg-[#111111] text-white border border-white/10 px-4 py-3 rounded-xl focus:outline-none focus:border-[#FF6B00] transition appearance-none"
                    >
                      {dateOptions.map(opt => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
                    </select>

                    <select 
                      required
                      value={timeSlot}
                      onChange={(e) => setTimeSlot(e.target.value)}
                      className="w-full bg-[#111111] text-white border border-white/10 px-4 py-3 rounded-xl focus:outline-none focus:border-[#FF6B00] transition appearance-none"
                    >
                      <option value="" disabled>Время *</option>
                      {availableTimeSlots.map((slot) => (
                        <option key={slot} value={slot}>{slot}</option>
                      ))}
                    </select>
                  </div>

                  <div className="flex gap-2 pb-2">
                     <label className={`flex items-center gap-2 flex-1 cursor-pointer bg-[#111111] border px-4 py-3 rounded-xl transition ${payment === "cash" ? "border-[#FF6B00] text-white" : "border-white/10 text-neutral-400"}`}>
                        <input type="radio" checked={payment === "cash"} onChange={() => setPayment("cash")} className="hidden" />
                        <div className={`w-4 h-4 rounded-full border-2 flex items-center justify-center ${payment === "cash" ? "border-[#FF6B00]" : "border-neutral-500"}`}>
                          {payment === "cash" && <div className="w-2 h-2 rounded-full bg-[#FF6B00]" />}
                        </div>
                        <span className="text-sm font-medium leading-none mt-0.5">Наличными</span>
                     </label>
                     <label className={`flex items-center gap-2 flex-1 cursor-pointer bg-[#111111] border px-4 py-3 rounded-xl transition ${payment === "bit" ? "border-[#FF6B00] text-white" : "border-white/10 text-neutral-400"}`}>
                        <input type="radio" checked={payment === "bit"} onChange={() => setPayment("bit")} className="hidden" />
                        <div className={`w-4 h-4 rounded-full border-2 flex items-center justify-center ${payment === "bit" ? "border-[#FF6B00]" : "border-neutral-500"}`}>
                          {payment === "bit" && <div className="w-2 h-2 rounded-full bg-[#FF6B00]" />}
                        </div>
                        <span className="text-sm font-medium leading-none mt-0.5">Bit / Перевод</span>
                     </label>
                  </div>

                  <div className="flex justify-between items-center py-2 text-white">
                    <span className="text-neutral-400 font-medium">Итого:</span>
                    <span className="text-3xl font-extrabold">{finalTotal} ₪</span>
                  </div>

                  <button 
                    type="submit" 
                    disabled={isSubmitting}
                    className="w-full bg-gradient-to-r from-[#FF6B00] to-[#FF8C38] text-white font-extrabold py-4 rounded-xl flex items-center justify-center gap-2 transition disabled:opacity-50 shadow-[0_4px_16px_rgba(255,107,0,0.4)]"
                  >
                    {isSubmitting ? <Loader2 className="w-5 h-5 animate-spin" /> : "Оформить заказ"}
                  </button>
                </form>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}

import { DbRow } from '@borsch/types';
import { create } from 'zustand';
import { useInventoryStore } from './useInventoryStore';
import { useOrdersStore } from './useOrdersStore';
import { useMenuStore } from './useMenuStore';
import { useRecipesStore } from './useRecipesStore';
import { useAssembliesStore } from './useAssembliesStore';
import { getDb } from '@borsch/db-local';
import { invoke } from '@tauri-apps/api/core';

export type Sender = 'user' | 'ai' | 'system';

export interface AiMessage {
  id: string;
  text: string;
  sender: Sender;
  isLoading?: boolean;
  imagePath?: string;
  functionResponse?: Record<string, unknown>;
}

interface AiState {
  messages: AiMessage[];
  isOpen: boolean;
  isInitializing: boolean;

  togglePanel: () => void;
  openPanel: () => void;
  closePanel: () => void;

  sendMessage: (text: string, currentPath: string, imageBase64?: string, mimeType?: string) => Promise<void>;
  clearHistory: () => void;
}

