export const useAiStore = create<AiState>((set, get) => ({
  messages: [
    {
      id: 'init',
      text: 'Привет! Я ИИ-ассистент Borsch Shop. Могу проанализировать продажи или помочь со складом.',
      sender: 'system'
    }
  ],
  isOpen: false,
  isInitializing: false,

  togglePanel: () => set(state => ({ isOpen: !state.isOpen })),
  openPanel: () => set({ isOpen: true }),
  closePanel: () => set({ isOpen: false }),
  clearHistory: () => {
    set({
      messages: [{ id: 'init', text: 'История очищена.', sender: 'system' }]
    });
  },

  sendMessage: async (text: string, currentPath: string, imageBase64?: string, mimeType?: string) => {
    const contextPrefix = `[ТЕКУЩАЯ СТРАНИЦА: ${currentPath}]. `;
    const fullText = (currentPath && text ? contextPrefix : '') + text;

    // if not a system function callback, add message to UI
    if (!get().messages.find(m => m.functionResponse && m.text === fullText)) {
      const newMessage: AiMessage = {
        id: Date.now().toString(),
        text: fullText,
        sender: 'user',
        imagePath: imageBase64 ? `data:${mimeType};base64,${imageBase64}` : undefined,
      };
      set(state => ({ messages: [...state.messages, newMessage] }));
    }

    const loadingMessage: AiMessage = {
      id: Date.now().toString() + '_loading',
      text: 'Думаю...',
      sender: 'ai',
      isLoading: true
    };
    set(state => ({ messages: [...state.messages, loadingMessage] }));

    try {
      const messagesToSend = get().messages.filter(m => m.sender !== 'system' && !m.isLoading).map(m => ({
         sender: m.sender,
         text: m.text,
         functionResponse: m.functionResponse,
      }));

      const db = await getDb();
      const settingsResult: DbRow[] = await db.select("SELECT * FROM ai_settings LIMIT 1");
      const apiKey = settingsResult[0]?.api_key;
      const systemInstruction = (settingsResult[0]?.prompt_base || "") + " " + (settingsResult[0]?.prompt_custom || "") + " ЗАПРЕЩЕНО: " + (settingsResult[0]?.prompt_forbidden || "");

      const provider = settingsResult[0]?.provider || 'gemini';
      const baseUrl = settingsResult[0]?.base_url;
      const modelName = settingsResult[0]?.model_name || 'gemini-2.5-flash';
      const isDev = !!settingsResult[0]?.is_developer_mode;

      let aiResponseText = '';
      let calls: DbRow[] = [];

      const filteredMessages = messagesToSend.filter(m => m.sender !== 'system');
      let lastUserText = '';
      if (filteredMessages.length > 0 && filteredMessages[filteredMessages.length - 1].sender === 'user') {
         lastUserText = filteredMessages[filteredMessages.length - 1].text;
         filteredMessages.pop();
      }

      const activeTools = createTools(isDev);

      if (provider === 'gemini') {
          if (!apiKey && !isDev) throw new Error("API ключ не настроен.");
          const { GoogleGenAI } = await import('@google/genai');
          const ai = new GoogleGenAI({ apiKey: apiKey || 'dummy' });
          const historyToSend = filteredMessages.map(m => {
            if (m.functionResponse) return { role: 'user', parts: [{ functionResponse: { name: m.functionResponse.name, response: m.functionResponse.response } }] };
            return { role: m.sender === 'user' ? 'user' : 'model', parts: [{ text: m.text }] };
          });
          const chat = ai.chats.create({
            model: modelName,
            config: { systemInstruction: systemInstruction, tools: [{ functionDeclarations: activeTools as never[] }], temperature: 0.2 },
            history: historyToSend as never[]
          });
          let promptToSend: any = lastUserText;
          if (imageBase64 && mimeType) promptToSend = [ { inlineData: { data: imageBase64, mimeType } }, lastUserText || "Look at this" ];
          const response = await chat.sendMessage({ message: promptToSend });
          aiResponseText = response.text || '';
          calls = response.functionCalls || [];
      } else {
          const { default: OpenAI } = await import('openai');
          const openai = new OpenAI({ apiKey: apiKey || 'dummy', baseURL: baseUrl || undefined, dangerouslyAllowBrowser: true });
          const oHistory: Record<string, unknown>[] = filteredMessages.map(m => {
             if (m.functionResponse) return { role: 'tool', tool_call_id: m.functionResponse.name, content: JSON.stringify(m.functionResponse.response) };
             return { role: m.sender === 'user' ? 'user' : 'assistant', content: m.text };
          });

          const contentArr: Record<string, unknown>[] = [{ type: 'text', text: lastUserText }];
          if (imageBase64 && mimeType) contentArr.push({ type: 'image_url', image_url: { url: `data:${mimeType};base64,${imageBase64}` } });

          oHistory.push({ role: 'user', content: contentArr });

          const response = await openai.chat.completions.create({
             model: modelName,
             temperature: 0.2,
             messages: [ { role: 'system', content: systemInstruction }, ...oHistory ] as never[],
             tools: activeTools.map((t) => ({ type: 'function', function: { name: (t as Record<string, unknown>).name, description: (t as Record<string, unknown>).description, parameters: (t as Record<string, unknown>).parameters || { type: 'object', properties: {} } } })) as never[]
          });

          const choice = response.choices[0].message;
          aiResponseText = choice.content || '';
          if (choice.tool_calls) {
             calls = choice.tool_calls.map((tc: any) => ({ name: tc.function.name, args: JSON.parse(tc.function.arguments) })) as unknown as DbRow[];
          }
      }

      if (calls && calls.length > 0) {
        set(state => ({
          messages: state.messages.map(m => m.id === loadingMessage.id ? { ...m, text: 'Выполняю команды...' } : m)
        }));

        for (const call of calls) {
           let functionResponse: Record<string, unknown> = {};
           try {
             if (call.name === 'get_inventory_state') {
                const items = useInventoryStore.getState().categories.flatMap(c => c.items);
                functionResponse = { data: items.map(i => ({ id: i.id, name: i.name, quantity: i.quantity, unit: i.unit })) };
             } else if (call.name === 'get_sales_today') {
                const orders = useOrdersStore.getState().orders;
                const today = new Date().toISOString().split('T')[0];
                const todayOrders = orders.filter(o => o.createdAt.startsWith(today));
                functionResponse = { data: todayOrders, total: todayOrders.reduce((a, b) => a + b.totalAmount, 0) };
             } else if (call.name === 'get_menu_items') {
                const menu = useMenuStore.getState().items;
                functionResponse = { data: menu.map(m => ({ name: m.name, price: m.price, id: m.id, categoryId: m.categoryId, recipeId: m.recipeId, assemblyId: m.assemblyId })) };
             } else if (call.name === 'get_current_page_context') {
                let contextData: Record<string, unknown> | unknown[] = { error: 'No specific context found' };
                if (currentPath === '/orders') contextData = { orders: useOrdersStore.getState().orders };
                if (currentPath === '/inventory') contextData = { categories: useInventoryStore.getState().categories.map(c => ({ id: c.id, name: c.name, items: c.items.map(i => ({ id: i.id, name: i.name })) })) };
                if (currentPath === '/menu') contextData = { menu: useMenuStore.getState().items, categories: useMenuStore.getState().categories };
                if (currentPath === '/recipes') contextData = { recipes: useRecipesStore.getState().recipes };
                if (currentPath === '/assemblies') contextData = { assemblies: useAssembliesStore.getState().assemblies };
                functionResponse = { data: contextData };
             } else if (call.name === 'get_recipes') {
                const recipes = useRecipesStore.getState().recipes;
                functionResponse = { data: recipes.map(r => ({ id: r.id, name: r.name, portions: r.portions, ingredients: r.ingredients.map(i => ({ invId: i.inventoryItemId, name: i.inventoryItem?.name, qty: i.quantity, price: i.inventoryItem?.price })) })) };
             } else if (call.name === 'get_assemblies') {
                const assemblies = useAssembliesStore.getState().assemblies;
                functionResponse = { data: assemblies.map(a => ({ id: a.id, name: a.name, items: a.items.map(i => ({ invId: i.inventoryItemId, name: i.name, qty: i.quantity })) })) };
             } else if (call.name === 'get_sales_analytics') {
                const args = call.args as Record<string, string>;
                const db = await getDb();
                const dbData: DbRow[] = await db.select(
                  "SELECT id, created_at, total_amount, status FROM orders WHERE created_at >= $1 AND created_at <= $2",
                  [args.start_date, args.end_date + 'T23:59:59Z']
                );
                functionResponse = { data: dbData || [], total: (dbData || []).reduce((sum, o) => sum + (Number(o.total_amount) || 0), 0) };
             } else if (call.name === 'process_supplier_receipt') {
                const args = call.args as Record<string, unknown>;
                functionResponse = { success: true, parsed_items: args.items, message: 'Распознано успешно!' };
             } else if (call.name === 'update_inventory_item') {
                const args = call.args as Record<string, unknown>;
                if (args.id) {
                   const db = await getDb();
                   if (args.name !== undefined) await db.execute("UPDATE inventory_items SET name = $1, sync_status = 'pending_update' WHERE id = $2", [args.name, args.id]);
                   if (args.quantity !== undefined) await db.execute("UPDATE inventory_items SET stock = $1, sync_status = 'pending_update' WHERE id = $2", [args.quantity, args.id]);
                   if (args.price !== undefined) await db.execute("UPDATE inventory_items SET price = $1, sync_status = 'pending_update' WHERE id = $2", [args.price, args.id]);
                   await useInventoryStore.getState().fetchInventory();
                   functionResponse = { success: true, message: 'Товар обновлен' };
                } else {
                   functionResponse = { error: 'Не указан ID' };
                }
             } else if (call.name === 'send_telegram_message') {
                const args = call.args as Record<string, string>;
                const db = await getDb();
                const aiSettings: DbRow[] = await db.select("SELECT telegram_bot_token, telegram_chat_id FROM ai_settings LIMIT 1");
                const appSettings: DbRow[] = await db.select("SELECT telegram_chat_id FROM app_settings LIMIT 1");

                const botToken = aiSettings[0]?.telegram_bot_token;
                const chatId = appSettings[0]?.telegram_chat_id || aiSettings[0]?.telegram_chat_id;

                if (!botToken || !chatId) {
                   functionResponse = { error: 'Не настроен токен бота или chat_id в настройках приложения/AI.' };
                } else {
                   const res = await fetch("https://api.telegram.org/bot" + botToken + "/sendMessage", {
                     method: 'POST',
                     headers: { 'Content-Type': 'application/json' },
                     body: JSON.stringify({ chat_id: chatId, text: args.text, parse_mode: 'Markdown' })
                   });
                   const rJson = await res.json();
                   if (rJson.ok) {
                     functionResponse = { success: true, message: 'Отправлено в Telegram.' };
                   } else {
                     functionResponse = { error: 'Ошибка Telegram: ' + rJson.description };
                   }
                }
             } else if (call.name === 'get_low_stock_items') {
                const inventory = useInventoryStore.getState().categories.flatMap(c => c.items);
                const db = await getDb();
                const settings: DbRow[] = await db.select("SELECT low_stock_threshold_percent FROM app_settings LIMIT 1");
                // Default 15% if no settings
                const threshold = settings[0]?.low_stock_threshold_percent || 15;

                const dbItems: DbRow[] = await db.select("SELECT id, min_stock FROM inventory_items");

                const lowStockList = inventory.map(item => {
                  const dbItem = dbItems.find(i => i.id === item.id);
                  const minStock = dbItem?.min_stock && typeof dbItem.min_stock === 'number' && dbItem.min_stock > 0 ? dbItem.min_stock : (item.packSize || 10) * (threshold / 100);
                  return { ...item, minStock };
                }).filter(item => item.quantity <= item.minStock);

                functionResponse = { threshold_percent: threshold, lowStockList: lowStockList.map(i => ({ id: i.id, name: i.name, current: i.quantity, minimum_required: i.minStock })) };
             } else if (call.name === 'read_local_file') {
                const args = call.args as Record<string, string>;
                const result = await invoke('read_local_file', { path: args.path, devMode: true });
                functionResponse = { data: result };
             } else if (call.name === 'write_local_file') {
                const args = call.args as Record<string, string>;
                await invoke('write_local_file', { path: args.path, content: args.content, devMode: true });
                functionResponse = { success: true };
             } else if (call.name === 'execute_local_command') {
                const args = call.args as Record<string, unknown>;
                const result = await invoke('execute_local_command', { cmd: args.cmd, args: args.args || [], devMode: true });
                functionResponse = { output: result };
             } else if (call.name === 'mutate_page_data') {
                const args = call.args as Record<string, unknown>;
                const payloadStr = typeof args.payload === 'string' ? args.payload : JSON.stringify(args.payload);
                const payload = JSON.parse(payloadStr) as Record<string, unknown>;

                if (args.entity === 'inventory') {
                  if (args.action === 'add') {
                     await useInventoryStore.getState().saveItem({ id: '', name: String(payload.name), categoryId: String(payload.categoryId), unit: String(payload.unit || 'шт'), price: Number(payload.price || 0), quantity: Number(payload.quantity || payload.stock || 0), supplier: String(payload.supplier || ''), packSize: Number(payload.packSize || 1) });
                  } else if (args.id) {
                     await useInventoryStore.getState().saveItem({ id: String(args.id), ...(payload as any) });
                  }
                } else if (args.entity === 'menu') {
                  if (args.action === 'add') {
                     await useMenuStore.getState().saveMenuItem({ id: '', name: String(payload.name), price: Number(payload.price), categoryId: String(payload.categoryId), recipeId: payload.recipeId ? String(payload.recipeId) : undefined, assemblyId: payload.assemblyId ? String(payload.assemblyId) : undefined, description: String(payload.description || ''), image: String(payload.image || ''), isActive: true, isPoll: Boolean(payload.isPoll || false) } as never);
                  } else if (args.id) {
                     await useMenuStore.getState().saveMenuItem({ id: String(args.id), ...(payload as any) });
                  }
                } else if (args.entity === 'recipe') {
                  if (args.action === 'add') {
                     await useRecipesStore.getState().addRecipe(String(payload.name), Number(payload.portions), (payload.ingredients || []) as any[]);
                  } else if (args.id) {
                     await useRecipesStore.getState().updateRecipe(String(args.id), String(payload.name), Number(payload.portions), (payload.ingredients || []) as any[]);
                  }
                } else if (args.entity === 'assembly') {
                  if (args.action === 'add') {
                     await useAssembliesStore.getState().addAssembly(String(payload.name), (payload.items || []) as any[]);
                  } else if (args.id) {
                     await useAssembliesStore.getState().updateAssembly(String(args.id), String(payload.name), (payload.items || []) as any[]);
                  }
                }
                functionResponse = { success: true };
             }
           } catch (e: unknown) {
               functionResponse = { error: (e as Error).message };
           }

           // Automatically send the tool response back as a recursive call
           set(state => ({
              messages: [
                 ...state.messages.filter(m => m.id !== loadingMessage.id),
                 { id: Date.now().toString() + Math.random(), text: "Function " + call.name + " executed", sender: 'user', functionResponse: { name: call.name, response: functionResponse } }
              ]
           }));
        }

        // Delay to allow state to settle
        await new Promise(r => setTimeout(r, 100));
        // Trigger next loop to send tool responses back
        await get().sendMessage(fullText, currentPath);
      } else {
        set(state => ({
          messages: [
            ...state.messages.filter(m => m.id !== loadingMessage.id),
            { id: Date.now().toString() + Math.random(), text: aiResponseText || 'Готово', sender: 'ai' }
          ]
        }));
      }

    } catch (e: unknown) {
      console.error(e);
      set(state => ({
        messages: [
          ...state.messages.filter(m => m.id !== loadingMessage.id),
          { id: Date.now().toString(), text: 'Сбой AI-агента: ' + (e as Error).message, sender: 'system' }
        ]
      }));
    }
  }
}));

import { DbRow, DbValues } from '@borsch/types';
import { create } from 'zustand';
import { getDb } from '@borsch/db-local';
import { generateId } from '@borsch/ui/utils';


export interface Shift {
  id: string;
  workerId: string;
  startTime: string; // ISO String
  endTime: string | null;
  totalHours: number;
  totalPay: number;
  status: 'open' | 'closed';
  createdAt: string;
  // Hydrated references
  workerName?: string;
  workerRate?: number;
}

interface ShiftsStore {
  shifts: Shift[];
  isLoading: boolean;
  error: string | null;
  fetchShifts: () => Promise<void>;
  openShift: (workerId: string) => Promise<void>;
  closeShift: (shiftId: string) => Promise<void>;
  deleteShift: (shiftId: string) => Promise<void>;
}

export const useShiftsStore = create<ShiftsStore>((set, get) => ({
  shifts: [],
  isLoading: false,
  error: null,

  fetchShifts: async () => {
    set({ isLoading: true, error: null });
    try {
      const db = await getDb();
      // We will join with workers to get the name and current rate
      const res = await db.select<DbRow[]>(`
        SELECT s.*, w.name as worker_name, w.rate_per_hour as worker_rate
        FROM shifts s
        LEFT JOIN workers w ON s.worker_id = w.id
        WHERE s.sync_status != 'pending_delete'
        ORDER BY s.status DESC, s.start_time DESC
      `);

      const shifts: Shift[] = res.map((r) => ({
        id: r.id,
        workerId: r.worker_id,
        startTime: r.start_time,
        endTime: r.end_time || null,
        totalHours: r.total_hours || 0,
        totalPay: r.total_pay || 0,
        status: r.status,
        createdAt: r.created_at,
        workerName: r.worker_name,
        workerRate: r.worker_rate || 0,
      }));
      set({ shifts, isLoading: false });
    } catch (err: unknown) {
      console.error('Failed to fetch shifts:', err);
      set({ error: (err as Error).message || 'Ошибка загрузки смен', isLoading: false });
    }
  },

  openShift: async (workerId) => {
    try {
      const db = await getDb();
      const id = generateId();
      const now = new Date().toISOString();
      await db.execute(
        `INSERT INTO shifts (id, worker_id, start_time, status, sync_status)
         VALUES ($1, $2, $3, 'open', 'pending_insert')`,
        [id, workerId, now]
      );
      get().fetchShifts();
    } catch (err: unknown) {
      console.error('Open shift err:', err);
      throw err;
    }
  },

  closeShift: async (shiftId) => {
    try {
      const state = get();
      const shift = state.shifts.find(s => s.id === shiftId);
      if (!shift) throw new Error('Смена не найдена');
      if (shift.status === 'closed') throw new Error('Смена уже закрыта');

      // Calculate pay
      const endTimeStr = new Date().toISOString();
      const start = new Date(shift.startTime);
      const end = new Date(endTimeStr);

      let totalHours = (end.getTime() - start.getTime()) / (1000 * 60 * 60);
      if (totalHours < 0) totalHours = 0; // sanity check

      const totalPay = totalHours * (shift.workerRate || 0);

      const db = await getDb();
      await db.execute(
        `UPDATE shifts 
         SET end_time = $1, total_hours = $2, total_pay = $3, status = 'closed', sync_status = 'pending_update' 
         WHERE id = $4`,
        [endTimeStr, totalHours, totalPay, shiftId]
      );
      get().fetchShifts();
    } catch (err: unknown) {
      console.error('Close shift err:', err);
      throw err;
    }
  },

  deleteShift: async (shiftId) => {
    try {
      const db = await getDb();
      await db.execute(
        "UPDATE shifts SET sync_status = 'pending_delete' WHERE id = $1",
        [shiftId]
      );
      get().fetchShifts();
    } catch (err: unknown) {
      console.error('Delete shift err:', err);
      throw err;
    }
  }
}));
